156	/// Compile all Python source files in site-packages to bytecode, to speed up the
157	/// initial run of any subsequent executions.
158	///
159	/// See the `--compile` option on `pip sync` and `pip install`.
160	pub(super) async fn compile_bytecode(
161	    venv: &PythonEnvironment,
162	    concurrency: &Concurrency,
163	    cache: &Cache,
164	    printer: Printer,
165	) -> anyhow::Result<()> {
166	    let start = std::time::Instant::now();
167	    let mut files = 0;
168	    for site_packages in venv.site_packages() {
169	        let site_packages = CWD.join(site_packages);
170	        if !site_packages.exists() {
171	            debug!(
172	                "Skipping non-existent site-packages directory: {}",
173	                site_packages.display()
174	            );
175	            continue;
176	        }
177	        files += compile_tree(
178	            &site_packages,
179	            venv.python_executable(),
180	            concurrency,
181	            cache.root(),
182	        )
183	        .await
184	        .with_context(|| {
185	            format!(
186	                "Failed to bytecode-compile Python file in: {}",
187	                site_packages.user_display()
188	            )
189	        })?;
190	    }
191	    let s = if files == 1 { "" } else { "s" };
192	    writeln!(
193	        printer.stderr(),
194	        "{}",
195	        format!(
196	            "Bytecode compiled {} {}",
197	            format!("{files} file{s}").bold(),
198	            format!("in {}", elapsed(start.elapsed())).dimmed()
199	        )
200	        .dimmed()
201	    )?;
202	    Ok(())
203	}
