205	/// A multicasting writer that writes to both the standard output and an output file, if present.
206	struct OutputWriter<'a> {
207	    stdout: Option<AutoStream<std::io::Stdout>>,
208	    output_file: Option<&'a Path>,
209	    buffer: Vec<u8>,
210	}
211	
212	impl<'a> OutputWriter<'a> {
213	    /// Create a new output writer.
214	    fn new(include_stdout: bool, output_file: Option<&'a Path>) -> Self {
215	        let stdout = include_stdout.then(|| AutoStream::<std::io::Stdout>::auto(stdout()));
216	        Self {
217	            stdout,
218	            output_file,
219	            buffer: Vec::new(),
220	        }
221	    }
222	
223	    /// Commit the buffer to the output file.
224	    async fn commit(self) -> std::io::Result<()> {
225	        if let Some(output_file) = self.output_file {
226	            if let Some(parent_dir) = output_file.parent() {
227	                fs_err::create_dir_all(parent_dir)?;
228	            }
229	
230	            // If the output file is an existing symlink, write to the destination instead.
231	            let output_file = fs_err::read_link(output_file)
232	                .map(Cow::Owned)
233	                .unwrap_or(Cow::Borrowed(output_file));
234	            let stream = anstream::adapter::strip_bytes(&self.buffer).into_vec();
235	            uv_fs::write_atomic(output_file, &stream).await?;
236	        }
237	        Ok(())
238	    }
239	}
240	
241	impl std::io::Write for OutputWriter<'_> {
242	    /// Write to both standard output and the output buffer, if present.
243	    fn write(&mut self, buf: &[u8]) -> std::io::Result<usize> {
244	        // Write to the buffer.
245	        if self.output_file.is_some() {
246	            self.buffer.write_all(buf)?;
247	        }
248	
249	        // Write to standard output.
250	        if let Some(stdout) = &mut self.stdout {
251	            stdout.write_all(buf)?;
252	        }
253	
254	        Ok(buf.len())
255	    }
256	
257	    fn flush(&mut self) -> std::io::Result<()> {
258	        if let Some(stdout) = &mut self.stdout {
259	            stdout.flush()?;
260	        }
261	        Ok(())
262	    }
263	}
