265	/// Given a list of names, return a conjunction of the names (e.g., "Alice, Bob, and Charlie").
266	pub(super) fn conjunction(names: Vec<String>) -> String {
267	    let mut names = names.into_iter();
268	    let first = names.next();
269	    let last = names.next_back();
270	    match (first, last) {
271	        (Some(first), Some(last)) => {
272	            let mut result = first;
273	            let mut comma = false;
274	            for name in names {
275	                result.push_str(", ");
276	                result.push_str(&name);
277	                comma = true;
278	            }
279	            if comma {
280	                result.push_str(", and ");
281	            } else {
282	                result.push_str(" and ");
283	            }
284	            result.push_str(&last);
285	            result
286	        }
287	        (Some(first), None) => first,
288	        _ => String::new(),
289	    }
290	}
