292	/// Capitalize the first letter of a string.
293	pub(super) fn capitalize(s: &str) -> String {
294	    let mut chars = s.chars();
295	    match chars.next() {
296	        None => String::new(),
297	        Some(c) => c.to_uppercase().collect::<String>() + chars.as_str(),
298	    }
299	}
