9	#[derive(Parser, Debug, Clone)]
10	#[command(next_help_heading = "Cache options")]
11	pub struct CacheArgs {
12	    /// Avoid reading from or writing to the cache, instead using a temporary directory for the
13	    /// duration of the operation.
14	    #[arg(
15	        global = true,
16	        long,
17	        short,
18	        alias = "no-cache-dir",
19	        env = EnvVars::UV_NO_CACHE,
20	        value_parser = clap::builder::BoolishValueParser::new(),
21	    )]
22	    pub no_cache: bool,
23	
24	    /// Path to the cache directory.
25	    ///
26	    /// Defaults to `$XDG_CACHE_HOME/uv` or `$HOME/.cache/uv` on macOS and Linux, and
27	    /// `%LOCALAPPDATA%\uv\cache` on Windows.
28	    ///
29	    /// To view the location of the cache directory, run `uv cache dir`.
30	    #[arg(global = true, long, env = EnvVars::UV_CACHE_DIR, value_hint = ValueHint::DirPath)]
31	    pub cache_dir: Option<PathBuf>,
32	}
33	
34	impl Cache {
35	    /// Prefer, in order:
36	    ///
37	    /// 1. A temporary cache directory, if the user requested `--no-cache`.
38	    /// 2. The specific cache directory specified by the user via `--cache-dir` or `UV_CACHE_DIR`.
39	    /// 3. The system-appropriate cache directory.
40	    /// 4. A `.uv_cache` directory in the current working directory.
41	    ///
42	    /// Returns an absolute cache dir.
43	    pub fn from_settings(no_cache: bool, cache_dir: Option<PathBuf>) -> Result<Self, io::Error> {
44	        if no_cache {
45	            Self::temp()
46	        } else if let Some(cache_dir) = cache_dir {
47	            Ok(Self::from_path(cache_dir))
48	        } else if let Some(cache_dir) = uv_dirs::legacy_user_cache_dir().filter(|dir| dir.exists())
49	        {
50	            // If the user has an existing directory at (e.g.) `/Users/user/Library/Caches/uv`,
51	            // respect it for backwards compatibility. Otherwise, prefer the XDG strategy, even on
52	            // macOS.
53	            Ok(Self::from_path(cache_dir))
54	        } else if let Some(cache_dir) = uv_dirs::user_cache_dir() {
55	            if cfg!(windows) {
56	                // On Windows, we append `cache` to the LocalAppData directory, i.e., prefer
57	                // `C:\Users\User\AppData\Local\uv\cache` over `C:\Users\User\AppData\Local\uv`.
58	                //
59	                // Unfortunately, v0.3.0 and v0.3.1 used the latter, so we need to migrate the cache
60	                // for those users.
61	                let destination = cache_dir.join("cache");
62	                let source = cache_dir;
63	                if let Err(err) = migrate_windows_cache(&source, &destination) {
64	                    warn!(
65	                        "Failed to migrate cache from `{}` to `{}`: {err}",
66	                        source.display(),
67	                        destination.display()
68	                    );
69	                }
70	
71	                Ok(Self::from_path(destination))
72	            } else {
73	                Ok(Self::from_path(cache_dir))
74	            }
75	        } else {
76	            Ok(Self::from_path(".uv_cache"))
77	        }
78	    }
79	}
80	
81	impl TryFrom<CacheArgs> for Cache {
82	    type Error = io::Error;
83	
84	    fn try_from(value: CacheArgs) -> Result<Self, Self::Error> {
85	        Self::from_settings(value.no_cache, value.cache_dir)
86	    }
87	}
88	
89	/// Migrate the Windows cache from `C:\Users\User\AppData\Local\uv` to `C:\Users\User\AppData\Local\uv\cache`.
90	fn migrate_windows_cache(source: &Path, destination: &Path) -> Result<(), io::Error> {
91	    // The list of expected cache buckets in v0.3.0.
92	    for directory in [
93	        "built-wheels-v3",
94	        "flat-index-v0",
95	        "git-v0",
96	        "interpreter-v2",
97	        "simple-v12",
98	        "wheels-v1",
99	        "archive-v0",
100	        "builds-v0",
101	        "environments-v1",
102	    ] {
103	        let source = source.join(directory);
104	        let destination = destination.join(directory);
105	
106	        // Migrate the cache bucket.
107	        if source.exists() {
108	            debug!(
109	                "Migrating cache bucket from {} to {}",
110	                source.display(),
111	                destination.display()
112	            );
113	            if let Some(parent) = destination.parent() {
114	                fs_err::create_dir_all(parent)?;
115	            }
116	            fs_err::rename(&source, &destination)?;
117	        }
118	    }
119	
120	    // The list of expected cache files in v0.3.0.
121	    for file in [".gitignore", "CACHEDIR.TAG"] {
122	        let source = source.join(file);
123	        let destination = destination.join(file);
124	
125	        // Migrate the cache file.
126	        if source.exists() {
127	            debug!(
128	                "Migrating cache file from {} to {}",
129	                source.display(),
130	                destination.display()
131	            );
132	            if let Some(parent) = destination.parent() {
133	                fs_err::create_dir_all(parent)?;
134	            }
135	            fs_err::rename(&source, &destination)?;
136	        }
137	    }
138	
139	    Ok(())
140	}
