    /// Only install the given package(s).
    #[arg(
        long,
        conflicts_with = "frozen",
        conflicts_with = "no_sync",
        conflicts_with = "no_install_package",
        hide = true,
        value_hint = ValueHint::Other,
    )]
    pub only_install_package: Vec<PackageName>,
}

