            let message = match InstallSource::detect() {
                Some(source) => format!(
                    "{base}\n\n{hint}{colon} You installed uv using {}. To update uv, run `{}`",
                    source.description(),
                    source.update_instructions().green(),
                    hint = "hint".bold().cyan(),
                    colon = ":".bold(),
                    base = BASE_MESSAGE
