use std::fmt::Write;

use anyhow::Result;
use diskus::DiskUsage;

use crate::commands::{ExitStatus, human_readable_bytes};
use crate::printer::Printer;
use uv_cache::{Cache, CacheBucket};
use uv_preview::{Preview, PreviewFeature};
use uv_warnings::warn_user;

/// Format a byte count for display, using human-readable format if requested.
fn format_size(bytes: u64, human_readable: bool) -> String {
    if human_readable {
        if bytes == 0 {
            "0B".to_string()
        } else {
            let (quantity, unit) = human_readable_bytes(bytes);
            format!("{quantity:.1}{unit}")
        }
    } else {
        format!("{bytes}")
    }
}

/// Display per-bucket cache usage statistics with a total at the end.
pub(crate) fn cache_stats(
    cache: &Cache,
    human_readable: bool,
    printer: Printer,
    preview: Preview,
) -> Result<ExitStatus> {
    if !preview.is_enabled(PreviewFeature::CacheSize) {
        warn_user!(
            "`uv cache stats` is experimental and may change without warning. Pass `--preview-features {}` to disable this warning.",
            PreviewFeature::CacheSize
        );
    }

    if !cache.root().exists() {
        for bucket in CacheBucket::iter() {
            writeln!(
                printer.stdout_important(),
                "{}: {}",
                bucket.name(),
                format_size(0, human_readable)
            )?;
        }
        writeln!(
            printer.stdout_important(),
            "Total: {}",
            format_size(0, human_readable)
        )?;
        return Ok(ExitStatus::Success);
    }

    let mut total_bytes: u64 = 0;

    for bucket in CacheBucket::iter() {
        let bucket_path = cache.bucket(bucket);
        let bucket_bytes = if bucket_path.exists() {
            let disk_usage = DiskUsage::new(vec![bucket_path]);
            disk_usage.count_ignoring_errors()
        } else {
            0
        };
        total_bytes += bucket_bytes;

        writeln!(
            printer.stdout_important(),
            "{}: {}",
            bucket.name(),
            format_size(bucket_bytes, human_readable)
        )?;
    }

    writeln!(
        printer.stdout_important(),
        "Total: {}",
        format_size(total_bytes, human_readable)
    )?;

    Ok(ExitStatus::Success)
}

