/// Add extra filtering for cache stats output (per-bucket and total lines).
#[must_use]
pub fn with_filtered_cache_stats(mut self) -> Self {
    // Filter "BucketName: <raw bytes>" lines
    self.filters.push((
        r"(?m)^([A-Za-z ]+): \d+$".to_string(),
        "$1: [SIZE]".to_string(),
    ));
    // Filter "BucketName: <human-readable size>" lines (e.g., "Wheels: 384.2KiB")
    self.filters.push((
        r"(?m)^([A-Za-z ]+): \d+(\.\d+)?[KMGT]i?B$".to_string(),
        "$1: [SIZE]".to_string(),
    ));
    self
}

